#!/usr/bin/env python3
"""Bundle highlight.js's CommonJS tree into one browser-loadable ESM file.

The npm package ships `es/index.js` as `import HighlightJS from '../lib/index.js'`,
and `lib/index.js` is CommonJS. A browser importing it fails with:

    SyntaxError: The requested module '../lib/index.js' does not provide an
    export named 'default'

There is no browser ESM build in the tarball, and this project may not run npm or
webpack. So walk `require()` from an entry module, wrap each module's bytes verbatim
in a function, and emit a single `hljs.mjs` with a tiny CommonJS shim. Source bytes
are never rewritten, which keeps the vendored code auditable against upstream.

Entry is `lib/common.js` (36 languages), not `lib/index.js` (all 384): the full set
costs 428,487 gzipped bytes against the application wasm's 20,410. `highlightAuto`
still runs, over the registered set. EXTRA_LANGUAGES adds grammars common.js omits.

highlight.js ships no Zig grammar, so Zig code blocks fall back to plaintext.

Usage: python3 vendor-hljs.py [path/to/node_modules/highlight.js] [out.mjs]
"""

import gzip
import json
import pathlib
import re
import sys

REQUIRE_RE = re.compile(r"""require\(\s*['"]([^'"]+)['"]\s*\)""")

ENTRY = "common.js"
EXTRA_LANGUAGES = ("nix",)

PRELUDE = """\
// Generated by vendor-hljs.py from highlight.js {version}. Do not edit by hand.
// Regenerate: python3 vendor-hljs.py
const __mods = {{}};
const __cache = {{}};

function __dir(id) {{
  const i = id.lastIndexOf('/');
  return i < 0 ? '' : id.slice(0, i);
}}

function __resolve(dir, id) {{
  if (id.charCodeAt(0) !== 46) return id;
  const parts = (dir ? dir.split('/') : []).concat(id.split('/'));
  const out = [];
  for (const p of parts) {{
    if (p === '' || p === '.') continue;
    if (p === '..') out.pop();
    else out.push(p);
  }}
  let r = out.join('/');
  if (!(r in __mods) && (r + '.js') in __mods) r += '.js';
  return r;
}}

function __require(id) {{
  const hit = __cache[id];
  if (hit) return hit.exports;
  const m = {{ exports: {{}} }};
  __cache[id] = m;
  const dir = __dir(id);
  __mods[id](m, m.exports, (rid) => __require(__resolve(dir, rid)));
  return m.exports;
}}
"""


def resolve(lib_root, importer, spec):
    target = (lib_root / importer).parent / spec
    for candidate in (target, target.with_name(target.name + ".js")):
        if candidate.is_file():
            return candidate.relative_to(lib_root).as_posix()
    raise SystemExit(f"unresolved require({spec!r}) from {importer}")


def main():
    pkg = pathlib.Path(sys.argv[1] if len(sys.argv) > 1 else "../../../node_modules/highlight.js").resolve()
    out_path = pathlib.Path(sys.argv[2] if len(sys.argv) > 2 else "hljs.mjs").resolve()
    lib_root = pkg / "lib"
    version = json.loads((pkg / "package.json").read_text())["version"]

    extras = [f"languages/{name}.js" for name in EXTRA_LANGUAGES]
    modules, pending = {}, [ENTRY, *extras]
    while pending:
        mid = pending.pop()
        if mid in modules:
            continue
        src = (lib_root / mid).read_text()
        modules[mid] = src
        for spec in REQUIRE_RE.findall(src):
            dep = resolve(lib_root, mid, spec)
            if dep not in modules:
                pending.append(dep)

    chunks = [PRELUDE.format(version=version)]
    for mid in sorted(modules):
        chunks.append(f"__mods[{json.dumps(mid)}] = function (module, exports, require) {{\n{modules[mid]}\n}};\n")
    chunks.append(f"\nconst hljs = __require({json.dumps(ENTRY)});\n")
    for name in EXTRA_LANGUAGES:
        chunks.append(f"hljs.registerLanguage({json.dumps(name)}, __require({json.dumps('languages/' + name + '.js')}));\n")
    chunks.append("export default hljs;\nexport { hljs };\n")

    out_path.write_text("".join(chunks))
    raw = out_path.stat().st_size
    gz = len(gzip.compress(out_path.read_bytes(), 9))
    print(f"hljs {version}: {len(modules)} modules, entry {ENTRY} + {list(EXTRA_LANGUAGES)}")
    print(f"  {out_path} raw={raw} gzip={gz}")


if __name__ == "__main__":
    main()
